// Transform family insurance data
const items = $input.all();
const transformedItems = [];

for (const item of items) {
  const data = item.json.body || item.json;

  // Calculate data completeness percentage
  const fields = ['firstName', 'lastName', 'age', 'city', 'email', 'phone', 'income', 'profession'];
  const filledFields = fields.filter(field => data[field] && data[field] !== null && data[field] !== '');
  const dataCompleteness = Math.round((filledFields.length / fields.length) * 100);

  // Clean and transform the data
  const transformed = {
    ...data,
    // Clean phone numbers to Israeli format
    phone: data.phone ? data.phone.replace(/[^0-9]/g, '').replace(/^0/, '+972-') : null,

    // Standardize monetary values to NIS
    income: data.income ? parseFloat(data.income.toString().replace(/[^0-9.]/g, '')) : 0,

    // Add defaults for missing fields
    familyId: data.familyId || `family_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    familySize: data.familySize || 1,

    // Validate phone numbers
    phoneValidated: data.phone ? /^\+972-[0-9]{2}-[0-9]{3}-[0-9]{4}$/.test(data.phone.replace(/[^0-9]/g, '').replace(/^0/, '+972-')) : false,

    // Calculate data quality score
    dataQuality: dataCompleteness,

    // Add timestamp
    processedAt: new Date().toISOString()
  };

  transformedItems.push({ json: transformed });
}

return transformedItems;

